mapper.update:
UPDATE user_push_tokens
SET enabled = FALSE,
    updated_at = NOW()
WHERE user_id = #{userId}
  AND token = #{token}

mapper.select:
SELECT EXISTS (
  SELECT 1
  FROM chat_notification_mutes
  WHERE room_id = #{roomId}
    AND user_id = #{userId}
)

mapper.insert:
INSERT INTO chat_notification_mutes (
  room_id,
  user_id
) VALUES (
  #{roomId},
  #{userId}
)
ON CONFLICT (room_id, user_id)
DO UPDATE SET muted_at = NOW()

mapper.delete:
DELETE FROM chat_notification_mutes
WHERE room_id = #{roomId}
  AND user_id = #{userId}
